import pytest
from solution import timeit

@timeit
def add(x, y):
    """Add two numbers."""
    return x + y

def test_returns_wrapped_value():
    assert add(2, 3) == 5

def test_records_last_elapsed_as_float():
    add(1, 1)
    assert isinstance(add.last_elapsed, float)
    assert add.last_elapsed >= 0

def test_wraps_preserves_name_and_doc():
    assert add.__name__ == 'add'
    assert add.__doc__ == 'Add two numbers.'

def test_accepts_kwargs():
    assert add(x=2, y=4) == 6

